def hamiltonian_derivatives(theta1, theta2, p1, p2):
    """Compute time derivatives using Hamiltonian mechanics"""
    cos_diff = math.cos(theta1 - theta2)
    sin_diff = math.sin(theta1 - theta2)
    den = 1 + sin_diff ** 2

